function.body:
TYPE RECORD IS REF CURSOR;
    Cur_Params RECORD;
    recordTrx RECORD;

    p_record_id VARCHAR(60);
    p_docAction VARCHAR(60);
    p_user VARCHAR(60);

    v_Result NUMBER:=1; --  Success
    v_ResultStr VARCHAR2(2000):='';
    v_Message VARCHAR2(2000):='';


  BEGIN
    v_Result:=1;
    --  Get Parameters
    v_ResultStr:='ReadingParameters';
    FOR Cur_Params IN (
        SELECT
            i.Record_ID,
            p.ParameterName,
            p.P_String,
            p.P_Number,
            p.P_Date,
            i.Ad_User_Id
        FROM
            AD_PInstance i
        LEFT JOIN AD_PInstance_Para p ON i.AD_PInstance_ID = p.AD_PInstance_ID
        WHERE
            i.AD_PInstance_ID = p_pinstance_id
        ORDER BY
            p.SeqNo
        )
    LOOP
      p_record_id := Cur_Params.Record_ID;
      p_user := Cur_Params.Ad_User_Id;
    END LOOP;

    -- Get Parameter
    DBMS_OUTPUT.PUT_LINE('  p_record_id=' || p_record_id) ;

    -- Consulta de estado actual
    SELECT
        aem_email_queue_id, status, validate_trx INTO recordTrx
    FROM
        aem_email_queue
    WHERE
        aem_email_queue_id = p_record_id;

    -- Cambio de estado
    UPDATE
        aem_email_queue
    SET
        status = CASE WHEN recordTrx.status = 'DR' THEN 'CO' ELSE 'DR' END,
        validate_trx = CASE WHEN recordTrx.validate_trx = 'AP' THEN 'RE' ELSE 'AP' END,
        UPDATED = now(),
        UPDATEDBY = p_user
    WHERE
        aem_email_queue_id = p_record_id;

    --  Update AD_PInstance
    DBMS_OUTPUT.PUT_LINE('Updating PInstance - Finished - ' || v_Message) ;
    AD_UPDATE_PINSTANCE(p_PInstance_ID, p_user, 'N', v_Result, v_Message) ;
    RETURN;
EXCEPTION
  WHEN OTHERS THEN
    v_ResultStr:= '@ERROR=' || SQLERRM;
    DBMS_OUTPUT.PUT_LINE(v_ResultStr) ;
    ROLLBACK;
    AD_UPDATE_PINSTANCE(p_PInstance_ID, NULL, 'N', 0, v_ResultStr) ;
    RETURN;
END AEM_VALIDATE_MAIL
